mapper.update:
begin
UPDATE T_BUS_HANDOVERLIST
DELIVERY_NUMBERS = #{entity.deliveryNumbers, jdbcType=VARCHAR}, CARGO_OWNER_ID = #{entity.cargoOwnerId, jdbcType=BIGINT} , CARGO_OWNER_NAME = #{entity.cargoOwnerName, jdbcType=VARCHAR}, cargo_code = #{entity.cargoCode,jdbcType=VARCHAR}, cargo_name = #{entity.cargoName,jdbcType=VARCHAR}, QUANTITY = #{entity.quantity, jdbcType=INTEGER}, TON = #{entity.ton, jdbcType=DECIMAL}, VOLUME_TON = #{entity.volumeTon, jdbcType=DECIMAL}, TICKET_NUM = #{entity.ticketNum, jdbcType=INTEGER}, REMARK = #{entity.remark, jdbcType=VARCHAR}, UPDATE_BY = #{entity.loginUserId, jdbcType=BIGINT}, UPDATE_BY_NAME = #{entity.loginUserName, jdbcType=VARCHAR}, UPDATE_TIME = #{entity.now}
id = #{entity.id};
end;

mapper.select:
SELECT
    A1.SHIPVOYAGE_ITEM_ID "shipvoyageItemId",A1.CARGO_NAME "cargoName",A1.TON "ton"
FROM T_BUS_HANDOVERLIST A1 LEFT JOIN T_BUS_CARGO_INFO A2 ON A1.CARGO_INFO_ID = A2.ID

    A1.SHIPVOYAGE_ITEM_ID IN (

        #{id}

    )

SELECT
sum(TBH.TON)
FROM T_DIS_SHIPVOYAGE_ITEM TDSI
JOIN T_DIS_SHIPVOYAGE TDS ON TDSI.SHIPVOYAGE_ID = TDS.ID
LEFT JOIN T_BUS_HANDOVERLIST TBH ON TDSI.ID = TBH.SHIPVOYAGE_ITEM_ID

    TDS.WHARF = '1' or TDS.WHARF is null

        AND TDSI.ID = #{shipvoyageItemId, jdbcType=BIGINT}



        AND ((TDS.SHIP_NAME || '_' || TDSI.VOYAGE) like #{shipOrVoyage_like, jdbcType=VARCHAR})


        AND TDSI.SHIP_STATUS_CODE = #{shipStatusCode, jdbcType=VARCHAR}


        and TDSI.CUSTOMER_ID = #{customerId}


        AND TDSI.CARGO_CATEGORY_NAME = #{cargoCategoryName, jdbcType=VARCHAR}


        AND TDS.LEAVE_PORT_TIME >= #{beginLeavePortTime,jdbcType=TIMESTAMP}


        AND TDS.LEAVE_PORT_TIME <= #{endLeavePortTime,jdbcType=TIMESTAMP}


        AND (TDS.IS_START_WORK IS NULL OR TDS.IS_START_WORK = #{isStartWork, jdbcType=VARCHAR})


        AND TDSI.ID IN (
        SELECT TBT.SHIPVOYAGE_ITEM_ID
        FROM T_BUS_TRUST TBT
        JOIN T_BUS_TRUST_CARGO TBTC ON TBT.ID = TBTC.TRUST_ID
        JOIN T_BUS_CARGO_INFO TBCI ON TBTC.CARGO_INFO_ID = TBCI.ID


            TBCI.CARGO_INFO_NO like #{cargoInfoNo_like, jdbcType=VARCHAR}

        )


ORDER BY CASE WHEN TDS.BERTH_TIME IS NULL THEN 1 ELSE 0 END ASC, TDS.BERTH_TIME DESC

mapper.update:
begin
update T_BUS_CARGO_INFO set DELIVERY_NUMBERS=#{item.deliveryNumbers,jdbcType=VARCHAR}, CARGO_OWNER_ID=#{item.cargoOwnerId}, CARGO_OWNER_NAME=#{item.cargoOwnerName}, CARGO_CODE=#{item.cargoCode}, CARGO_NAME=#{item.cargoName}, TRADE_TYPE=#{item.tradeType}, PACKING_CODE=#{item.packingCode}, PACKING_NAME=#{item.packingName}, COMPANY_ID=#{item.companyId}, COMPANY_NAME=#{item.companyName}, QUANTITY=#{item.quantity}, TON=#{item.ton}, RIGHTS_QUANTITY=#{item.rightsQuantity}, SURPLUS_RIGHTS_QUANTITY=#{item.surplusRightsQuantity}, VOYAGE=#{item.voyage}, HATCH_NUMS=#{item.hatchNums} where ID =#{item.id}
end;

mapper.select:
select TYTI.ID,TYTI.CARGO_INFO_ID,TYTI.TON,TYTI.QUANTITY from T_YARD_TALLY_ITEM TYTI left join T_YARD_TALLY TYT on TYT.id = TYTI.TALLY_ID left join M_WORK_PROCESS MWP on MWP.PROCESS_CD = TYT.PROCESS_CODE where (MWP.SOURCE_CD = '03'or MWP.TARGET_CD = '03') and TYT.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId,jdbcType=BIGINT} and EXISTS ( select * from (
select #{tmpId} as TMPID from dual
) a where a.TMPID = TYTI.CARGO_INFO_ID )

mapper.update:
begin

    update T_BUS_HANDOVERLIST
    SET
    TALLY_TON = #{item.tallyTon,jdbcType=DECIMAL},
    TALLY_QUANTITY = #{item.tallyQuantity,jdbcType=INTEGER} ,
    UPDATE_BY = #{item.loginUserId, jdbcType=BIGINT},
    UPDATE_BY_NAME = #{item.loginUserName, jdbcType=VARCHAR},
    UPDATE_TIME = #{item.now}
    WHERE ID =#{item.id}

end;
